class Bad {
    fun parseHeader(line: String): Int {
        return line.indexOf(":")
    }
}

class Bad {
    fun findLastSlash(path: String): Int {
        return path.lastIndexOf("/")
    }
}

class Good {
    fun parseHeader(line: String): Int {
        return line.indexOf(':')
    }
}

class Good {
    fun findSeparator(s: String): Int {
        return s.indexOf("::")
    }
}

class Bad {
    fun parsePath(path: String): Pair<Int, Int> {
        val start = path.indexOf("/")
        val end   = path.lastIndexOf("/")
        return Pair(start, end)
    }
}

class Good {
    fun findItem(items: List<String>): Int {
        return items.indexOf("x")
    }
}
